import { cursor } from './cursor';
import { gamePaused } from './gamePaused';
import { gameStore } from '../../../stores/gameStore';
import { derived } from 'svelte/store';

const state = gameStore.state; // 取出 state 派生 store

export const keyboardDisabled = derived(
	[cursor, state, gamePaused],
	([$cursor, $state, $gamePaused]) => {
		return (
			($cursor.x === null && $cursor.y === null) ||
			$state.grid[$cursor.y][$cursor.x] !== 0 ||
			$gamePaused
		);
	},
	false,
);